"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[3048],{4355:(e,d,r)=>{r.r(d),r.d(d,{data:()=>i});const i=JSON.parse('{"key":"v-74bb781c","path":"/proofreader-guide.html","title":"Инструкция по Proofreader","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[{"level":2,"title":"Этапы работы над книгой","slug":"этапы-работы-над-книгои","link":"#этапы-работы-над-книгои","children":[{"level":3,"title":"Вычитка","slug":"вычитка","link":"#вычитка","children":[]},{"level":3,"title":"Форматирование","slug":"форматирование","link":"#форматирование","children":[]},{"level":3,"title":"Проверка","slug":"проверка","link":"#проверка","children":[]}]},{"level":2,"title":"Пример работы в Proofreader","slug":"пример-работы-в-proofreader","link":"#пример-работы-в-proofreader","children":[]},{"level":2,"title":"Статусы","slug":"статусы","link":"#статусы","children":[{"level":3,"title":"Статусы страниц","slug":"статусы-страниц","link":"#статусы-страниц","children":[]},{"level":3,"title":"Статусы книг","slug":"статусы-книг","link":"#статусы-книг","children":[]}]},{"level":2,"title":"Функции","slug":"функции","link":"#функции","children":[{"level":3,"title":"Восстановление страницы из истории","slug":"восстановление-страницы-из-истории","link":"#восстановление-страницы-из-истории","children":[]}]},{"level":2,"title":"Настройки","slug":"настроики","link":"#настроики","children":[]},{"level":2,"title":"Группы пользователей","slug":"группы-пользователеи","link":"#группы-пользователеи","children":[]}],"git":{"updatedTime":1702985435000},"filePathRelative":"proofreader-guide.md"}')},6314:(e,d,r)=>{r.r(d),r.d(d,{default:()=>p});var i=r(6252);const a=(0,i._)("h1",{id:"инструкция-по-proofreader",tabindex:"-1"},[(0,i._)("a",{class:"header-anchor",href:"#инструкция-по-proofreader","aria-hidden":"true"},"#"),(0,i.Uk)(" Инструкция по Proofreader")],-1),l={class:"table-of-contents"},n=(0,i.uE)('<h2 id="этапы-работы-над-книгои" tabindex="-1"><a class="header-anchor" href="#этапы-работы-над-книгои" aria-hidden="true">#</a> Этапы работы над книгой</h2><p>Работа над книгой проходит в несколько этапов:</p><ol><li>Вычитка</li><li>Форматирование</li><li>Проверка</li></ol><h3 id="вычитка" tabindex="-1"><a class="header-anchor" href="#вычитка" aria-hidden="true">#</a> Вычитка</h3><p>Прежде всего исправьте опечатки распознавания: неверные буквы и лишние или недостающие знаки препинания.</p><p>Абзацы разделяются пустой строкой. Не нужно форматировать их дополнительно, например, добавлять пробелы. Просто разделяйте абзацы пустой строкой.</p><p>Пример, так правильно:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Истина мертвая становится врагом истины живой, развивающейся».\n\nОчевидно, история научного познания предстанет в ее действительном обогащенном содержании тогда и только тогда, когда...\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Так неправильно:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Истина мертвая становится врагом истины живой, развивающейся».\n\n    Очевидно, история научного познания предстанет в ее действительном обогащенном содержании тогда и только тогда, когда...\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Удаляйте лишние переводы строк, внутри абзаца не должно быть переводов строк. Один абзац — одна строка.</p><p>Пример, так правильно:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Реальный познавательный процесс не свободен от заблуждений. Поэтому научная разработка теории познания должна включать в себя и анализ заблуждений, имеющих место в познавательном процессе. Мы говорим об этом потому, что без исследования связи познания с заблуждением не является достаточно полным и само понимание истины.\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Так неправильно:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Реальный познавательный процесс не свободен от заблуждений.\nПоэтому научная разработка теории познания должна включать в себя и анализ заблуждений, имеющих место в познавательном процессе.\nМы говорим об этом потому, что без исследования связи познания с заблуждением не является достаточно полным и само понимание истины..\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Кнопка «Улучшить форматирование» в верхней части экрана автоматизирует форматирование. После автоматической оцифровки каждый абзац разделен на строки, а между абзацами есть дополнительный перевод строки:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Еще больший момент приблизительности в сравне-\nнии с ощущениями содержат восприятия и представле-\nния. Как показывают исследования, при восприятии\nпроисходит процесс соотнесения конкретно воспринима-\nемого предмета с образом в сознании. Эта процедура\nносит вероятностный характер и осуществляется по\nмере ознакомления воспринимающего с признаками\nпредмета.\n\nОтносительность, приблизительность отражения воз-\nрастают в случаях, когда субъект встречается с незна-\nкомым предметом или признаками его.\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>После нажатия кнопки строки одного абзаца автоматически соединятся в одну.</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Еще больший момент приблизительности в сравне- нии с ощущениями содержат восприятия и представле- ния. Как показывают исследования, при восприятии происходит процесс соотнесения конкретно воспринима- емого предмета с образом в сознании. Эта процедура носит вероятностный характер и осуществляется по мере ознакомления воспринимающего с признаками предмета.\n\nОтносительность, приблизительность отражения воз- растают в случаях, когда субъект встречается с незна- комым предметом или признаками его.\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>После этого останется правильно соединить слова которые переносились на следующую строку: <code>представле- ния</code> и <code>воспринима- емого</code>. В будущем, это, возможно, будет автоматизировано.</p><p>Не оставляйте номер страницы, удалите его из текста и внесите его в поле <code>Номер страницы в книге</code>.</p><h3 id="форматирование" tabindex="-1"><a class="header-anchor" href="#форматирование" aria-hidden="true">#</a> Форматирование</h3><p>На этапе форматирования текст книги приводится в соответствие формату <a href="%5Bformat-comtext.md%5D">Comtext</a>.</p><h3 id="проверка" tabindex="-1"><a class="header-anchor" href="#проверка" aria-hidden="true">#</a> Проверка</h3><p>Финальная проверка текста.</p><h2 id="пример-работы-в-proofreader" tabindex="-1"><a class="header-anchor" href="#пример-работы-в-proofreader" aria-hidden="true">#</a> Пример работы в Proofreader</h2><p>Пример вычитки одной страницы по шагам.</p>',27),o={href:"http://proofreader.comtext.space/",target:"_blank",rel:"noopener noreferrer"},t=(0,i.uE)('<p><img src="images/proofreader-guide/proofreader-guide01.png" alt=""></p><p>Введите <code>Имя пользователя</code> и <code>Пароль</code>, затем нажмите кнопку <code>Войти</code>.</p><p><img src="images/proofreader-guide/proofreader-guide02.png" alt=""></p><p>Откройте список страниц книг, для этого нажмите на кнопку Изменить в строке <code>Pages</code>.</p><p><img src="images/proofreader-guide/proofreader-guide03.png" alt=""></p><p>В правом меню выберите нужную книгу (1), после этого в таблице, в центре экрана, останутся только страницы выбранной книги. Затем выберите нужную страницу (2).</p><p>Чтобы распознанный текст книги и изображение страницы находились на одной высоте закройте левое меню с помощью сплиттера:</p><p><img src="images/proofreader-guide/proofreader-guide04.png" alt=""></p><p><img src="images/proofreader-guide/proofreader-guide05.png" alt=""></p><p>Чтобы вручную не удалять лишние переводы строк нажмите кнопку <code>Улучшить форматирование</code>. После этого абзацы склеятся в одну строку.</p><p><img src="images/proofreader-guide/proofreader-guide06.png" alt=""></p><p><img src="images/proofreader-guide/proofreader-guide07.png" alt=""></p><p>Исправьте опечатки в тексте книги, сверяясь с изображением страницы.</p><p><img src="images/proofreader-guide/proofreader-guide08.png" alt=""></p><p>Запишите номер страницы из книги (1) в поле <code>Номер страницы в книге</code> (2) и удалите номер из текста страницы (3).</p><p><img src="images/proofreader-guide/proofreader-guide09.png" alt=""></p><p>Установите статус <code>Форматирование</code>.</p><p><img src="images/proofreader-guide/proofreader-guide10.png" alt=""></p><p>Нажмите кнопки <code>Сохранить и продолжить редактирование</code> (1), а затем <code>Следующая страница</code> (2).</p><h2 id="статусы" tabindex="-1"><a class="header-anchor" href="#статусы" aria-hidden="true">#</a> Статусы</h2><h3 id="статусы-страниц" tabindex="-1"><a class="header-anchor" href="#статусы-страниц" aria-hidden="true">#</a> Статусы страниц</h3><p>Каждая страница книги находится в одном из статусов.</p><ul><li><code>Распознавание</code> — после добавления книги этот статус выставляется автоматически, в время распознавания происходит оцифровка изображения страницы и перевод его в текст.</li><li><code>Распознано</code> — после завершения распознавания текста, автоматически выставляется статус <code>Распознано</code>.</li><li><code>Вычитка</code> — на этом этапе редакторы устраняют в книге ошибки автоматического распознавания. После того как ошибки устранены книга переводится в следующий статус — <code>Форматирование</code>.</li><li><code>Форматирование</code> — на этом этапе редакторы форматируют книгу в формате <a href="%5Bformat-comtext.md%5D">Comtext</a>. После того как ошибки устранены книга переводится в следующий статус — <code>Проверка</code>.</li><li><code>Проверка</code> — проверка корректности вычитки и форматирования. После проверки страница переводится в статус <code>Завершено</code></li><li><code>Завершено</code> — окончательный статус страницы. Однако, при нахождении новых опечаток ничего не мешает исправить их, даже если книга находится в этом статусе.</li></ul><h3 id="статусы-книг" tabindex="-1"><a class="header-anchor" href="#статусы-книг" aria-hidden="true">#</a> Статусы книг</h3><p>Каждая книга находится в одном из трех состояний.</p><ul><li><code>Распознавание</code> — статус автоматически выставляется после добавление книги и так же автоматически книга переходит в следующий статус <code>Вычитка</code> после завершения распознавания всех страниц.</li><li><code>Вычитка</code> — основной этап работы над книгой. Книга переходит в следующее состояние <code>Завершено</code> когда все страницы книги в статусе <code>Завершено</code>.</li><li><code>Завершено</code> — окончательное состояние книги.</li></ul><h2 id="функции" tabindex="-1"><a class="header-anchor" href="#функции" aria-hidden="true">#</a> Функции</h2><h3 id="восстановление-страницы-из-истории" tabindex="-1"><a class="header-anchor" href="#восстановление-страницы-из-истории" aria-hidden="true">#</a> Восстановление страницы из истории</h3><p>Для восстановления предыдущей версии страницы из истории, нажмите на кнопку «История» в верхней части формы редактирования страницы.</p><p><img src="images/proofreader-guide/proofreader-guide15.png" alt=""></p><p>Найдите нужную версию и прейдите по ссылке на эту версию.</p><p><img src="images/proofreader-guide/proofreader-guide16.png" alt=""></p><p>Нажмите на кнопку «Восстановить» внизу страницы.</p><p><img src="images/proofreader-guide/proofreader-guide16.png" alt=""></p><h2 id="настроики" tabindex="-1"><a class="header-anchor" href="#настроики" aria-hidden="true">#</a> Настройки</h2><p>Настройки находятся в разделе «Настройки аккаунта»</p><p><img src="images/proofreader-guide/proofreader-guide11.png" alt=""></p><p>Параметр «Размер текста» определяет размер текста в редакторе на странице книги.</p><h2 id="группы-пользователеи" tabindex="-1"><a class="header-anchor" href="#группы-пользователеи" aria-hidden="true">#</a> Группы пользователей</h2><p>Сейчас в Proofreader четыре группы пользователей</p><ul><li>Читатель — могут просматривать авторов, книги и страницы, но не могут редактировать.</li><li>Корректор — могут просматривать авторов, книги и страницы, а так же редактировать страницы. При редактировании страниц доступны следующие статусы: <code>Распознано</code>, <code>Вычитка</code>, <code>Форматирование</code>. В этой группе находятся пользователи после регистрации.</li><li>Редактор — могут просматривать авторов, книги и страницы, а так же редактировать страницы. При редактировании страниц доступны все статусы.</li><li>Администраторы — занимаются настройкой системы и загрузкой книг.</li></ul><p>Менять группу пользователя могут только администраторы. Для изменения группы пользователя перейдите в пункт «Пользователи» и выберите пользователя.</p><p><img src="images/proofreader-guide/proofreader-guide12.png" alt=""></p><p><img src="images/proofreader-guide/proofreader-guide13.png" alt=""></p><p>В разделе «Права доступа» установите пользователю нужную группу.</p><p><img src="images/proofreader-guide/proofreader-guide14.png" alt=""></p>',46),c={},p=(0,r(3744).Z)(c,[["render",function(e,d){const r=(0,i.up)("router-link"),c=(0,i.up)("ExternalLinkIcon");return(0,i.wg)(),(0,i.iD)("div",null,[a,(0,i._)("nav",l,[(0,i._)("ul",null,[(0,i._)("li",null,[(0,i.Wm)(r,{to:"#этапы-работы-над-книгои"},{default:(0,i.w5)((()=>[(0,i.Uk)("Этапы работы над книгой")])),_:1}),(0,i._)("ul",null,[(0,i._)("li",null,[(0,i.Wm)(r,{to:"#вычитка"},{default:(0,i.w5)((()=>[(0,i.Uk)("Вычитка")])),_:1})]),(0,i._)("li",null,[(0,i.Wm)(r,{to:"#форматирование"},{default:(0,i.w5)((()=>[(0,i.Uk)("Форматирование")])),_:1})]),(0,i._)("li",null,[(0,i.Wm)(r,{to:"#проверка"},{default:(0,i.w5)((()=>[(0,i.Uk)("Проверка")])),_:1})])])]),(0,i._)("li",null,[(0,i.Wm)(r,{to:"#пример-работы-в-proofreader"},{default:(0,i.w5)((()=>[(0,i.Uk)("Пример работы в Proofreader")])),_:1})]),(0,i._)("li",null,[(0,i.Wm)(r,{to:"#статусы"},{default:(0,i.w5)((()=>[(0,i.Uk)("Статусы")])),_:1}),(0,i._)("ul",null,[(0,i._)("li",null,[(0,i.Wm)(r,{to:"#статусы-страниц"},{default:(0,i.w5)((()=>[(0,i.Uk)("Статусы страниц")])),_:1})]),(0,i._)("li",null,[(0,i.Wm)(r,{to:"#статусы-книг"},{default:(0,i.w5)((()=>[(0,i.Uk)("Статусы книг")])),_:1})])])]),(0,i._)("li",null,[(0,i.Wm)(r,{to:"#функции"},{default:(0,i.w5)((()=>[(0,i.Uk)("Функции")])),_:1}),(0,i._)("ul",null,[(0,i._)("li",null,[(0,i.Wm)(r,{to:"#восстановление-страницы-из-истории"},{default:(0,i.w5)((()=>[(0,i.Uk)("Восстановление страницы из истории")])),_:1})])])]),(0,i._)("li",null,[(0,i.Wm)(r,{to:"#настроики"},{default:(0,i.w5)((()=>[(0,i.Uk)("Настройки")])),_:1})]),(0,i._)("li",null,[(0,i.Wm)(r,{to:"#группы-пользователеи"},{default:(0,i.w5)((()=>[(0,i.Uk)("Группы пользователей")])),_:1})])])]),n,(0,i._)("p",null,[(0,i.Uk)("Откройте в браузере "),(0,i._)("a",o,[(0,i.Uk)("страницу входа в Proofreader"),(0,i.Wm)(c)]),(0,i.Uk)(".")]),t])}]])}}]);